import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import BikeCard from '../components/BikeCard';

const Bikes = () => {
  const [bikes, setBikes] = useState([]);
  const [loading, setLoading] = useState(true);
  const [filters, setFilters] = useState({
    category: '',
    search: ''
  });

  useEffect(() => {
    fetchBikes();
  }, [filters]);

  const fetchBikes = async () => {
    setLoading(true);
    try {
      const params = new URLSearchParams();
      if (filters.category) params.append('category', filters.category);
      if (filters.search) params.append('search', filters.search);

      const response = await fetch(`http://localhost:5000/api/bikes?${params}`);
      const result = await response.json();
      
      if (result.success) {
        setBikes(result.data);
      }
    } catch (error) {
      console.error('Error fetching bikes:', error);
    } finally {
      setLoading(false);
    }
  };

  const handleFilterChange = (key, value) => {
    setFilters(prev => ({
      ...prev,
      [key]: value
    }));
  };

  const clearFilters = () => {
    setFilters({
      category: '',
      search: ''
    });
  };

  return (
    <div className="section">
      <div className="section-title">
        <h2>Our Bike Collection</h2>
        <p>Choose from our wide range of premium bikes</p>
      </div>

      {/* Filter Section */}
      <div className="filter-section">
        <div className="filter-grid">
          <div className="form-group">
            <label className="form-label">Search Bikes</label>
            <input
              type="text"
              className="form-control"
              placeholder="Search by name or features..."
              value={filters.search}
              onChange={(e) => handleFilterChange('search', e.target.value)}
            />
          </div>

          <div className="form-group">
            <label className="form-label">Category</label>
            <select
              className="form-control form-select"
              value={filters.category}
              onChange={(e) => handleFilterChange('category', e.target.value)}
            >
              <option value="">All Categories</option>
              <option value="Sports">Sports</option>
              <option value="Cruiser">Cruiser</option>
              <option value="Commuter">Commuter</option>
            </select>
          </div>

          <div className="form-group">
            <label className="form-label">&nbsp;</label>
            <button 
              className="btn btn-outline" 
              onClick={clearFilters}
              style={{ width: '100%' }}
            >
              Clear Filters
            </button>
          </div>
        </div>
      </div>

      {/* Bikes Grid */}
      {loading ? (
        <div className="loading">
          <div className="spinner"></div>
        </div>
      ) : bikes.length > 0 ? (
        <div className="grid grid-3">
          {bikes.map(bike => (
            <BikeCard key={bike.id} bike={bike} />
          ))}
        </div>
      ) : (
        <div style={{ textAlign: 'center', padding: '4rem' }}>
          <h3>No bikes found</h3>
          <p>Try adjusting your search filters</p>
          <button className="btn btn-primary" onClick={clearFilters}>
            Clear Filters
          </button>
        </div>
      )}

      {/* Call to Action */}
      <div style={{ textAlign: 'center', marginTop: '4rem', padding: '3rem', background: 'var(--primary-color)', borderRadius: 'var(--border-radius)', color: 'var(--white)' }}>
        <h3 style={{ marginBottom: '1rem' }}>Can't Find What You're Looking For?</h3>
        <p style={{ marginBottom: '2rem', opacity: 0.9 }}>Contact us for special requests or premium bike options</p>
        <Link to="/contact" className="btn btn-secondary">Contact Us</Link>
      </div>
    </div>
  );
};

export default Bikes;
